import React, { useEffect, useState } from 'react';
import { db } from '../firebase';
import { useParams, useNavigate } from 'react-router-dom';
import { doc, getDoc, updateDoc, Timestamp } from 'firebase/firestore';

function EditPlayer() {
  const { playerId } = useParams();
  const navigate = useNavigate();
  const [playerData, setPlayerData] = useState(null);
  const [pinVerified, setPinVerified] = useState(false);

  useEffect(() => {
    const fetchPlayer = async () => {
      const playerRef = doc(db, 'players', playerId);
      const playerSnap = await getDoc(playerRef);
      if (playerSnap.exists()) {
        setPlayerData(playerSnap.data());
      } else {
        alert('Player not found');
        navigate('/players-management');
      }
    };

    fetchPlayer();
  }, [playerId, navigate]);

  const verifyPin = () => {
    const userPin = prompt("Enter PIN to edit:");
    if (userPin === playerData.pin) {
      setPinVerified(true);
    } else {
      alert("Incorrect PIN. Access denied.");
      navigate('/players-management');
    }
  };

  const handleChange = (e) => {
    setPlayerData({ ...playerData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const playerRef = doc(db, 'players', playerId);
      await updateDoc(playerRef, {
        ...playerData,
        updatedAt: Timestamp.now(),
      });
      alert('Player updated successfully!');
      navigate('/players-management');
    } catch (error) {
      console.error('Error updating player:', error);
    }
  };

  if (!playerData) return <p>Loading...</p>;
  if (!pinVerified) {
    verifyPin();
    return null;
  }

  return (
    <div style={styles.container}>
      <h1>Edit Player: {playerData.firstName} {playerData.lastName}</h1>
      <form onSubmit={handleSubmit} style={styles.form}>
        <input
          type="text"
          name="firstName"
          value={playerData.firstName}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <input
          type="text"
          name="lastName"
          value={playerData.lastName}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <input
          type="text"
          name="nationality"
          value={playerData.nationality}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <button type="submit" style={styles.button}>Update Player</button>
      </form>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
  },
  input: { padding: '10px', borderRadius: '5px' },
  button: { backgroundColor: '#386C0B', color: '#FFF', padding: '10px' },
};

export default EditPlayer;
